// User types
/**
 * Represents a user in the system.
 * Contains user identification, authentication details, and workspace preferences.
 */
export interface User {
  id: string;
  email: string;
  name: string;
  isSuperAdmin: boolean;
  lastWorkspaceId: string | null;
  createdAt: Date;
  updatedAt: Date;
}

// Re-export all types
/** User-related types including the User interface */
export * from './user.js';

